With.Query:

				SELECT {{
							Fields
								-Dimension: PointsOfSale 
									--Table: PointsOfSaleCte
								-Dimension: Products 
									--Table: ProductsCte
								-Dimension: Calendar 
									--Table:CalendarCte
								-WithComma
                		}}
                		SalesAnalysis.SalesQuantity, SalesAnalysis.SalesAmountTaxesIncluded, SalesAnalysis.SalesAmountTaxesExcluded,
                		SalesAnalysis.Refund
                	FROM Fact.SalesAnalysis
                	{{
                		InnerJoin 
                			-Dimension: PointsOfSale 
                				--Table: PointsOfSaleCte
							-Table:SalesAnalysis
							-On:PointOfSaleId-PointOfSaleId
                	}}
                	{{
                		InnerJoin 
                			-Dimension: Products 
                				--Table: ProductsCte
							-Table: SalesAnalysis
							-On: ProductId-ProductId
                	}}
                	{{
                		InnerJoin 
                			-Dimension: Calendar 
                				--Required
                				--Table: CalendarCte
							-Table:SalesAnalysis
							-On:Date-Date
                	}}
